// ─── SUPABASE ─────────────────────────────────────────────────────────────────
// El cliente de Supabase se carga desde index.html via CDN
// Si no está configurado, la app funciona igual con datos de ejemplo
const getSB = () => {
  try {
    const url  = window.__SB_URL__  || "";
    const anon = window.__SB_ANON__ || "";
    if(url && anon && window.supabase) return window.supabase.createClient(url, anon);
  } catch(e) {}
  return null;
};
const sb = getSB();

