          <div className="r2">
            <div className="fg">
              <label>Fecha</label>
              <input className="ii" type="date" value={saleForm.date} onChange={e=>setSaleForm({...saleForm,date:e.target.value})}/>
            </div>
            <div className="fg">
              <label>Hora</label>
              <input className="ii" type="time" value={saleForm.time} onChange={e=>setSaleForm({...saleForm,time:e.target.value})}/>
            </div>
          </div>
